import { useState, useEffect, useCallback, useRef } from 'react';
import { SignalingClient } from '../services/signaling/SignalingClient';
import { WebRTCClient } from '../services/webrtc/WebRTCClient';
import { mediaDevicesService } from '../services/webrtc/MediaDevices';
import { RemoteParticipant } from '../components/Video/VideoGrid';

interface UseWebRTCOptions {
  roomId: string;
  role: 'broadcaster' | 'viewer';
  userId: string;
}

interface UseWebRTCReturn {
  localStream: MediaStream | null;
  remoteStreams: Map<string, RemoteParticipant>;
  isConnected: boolean;
  error: string | null;
  startMedia: () => Promise<void>;
  stopMedia: () => void;
  leave: () => void;
  signalingClient: SignalingClient | null;
}

export function useWebRTC({ roomId, role, userId }: UseWebRTCOptions): UseWebRTCReturn {
  const [localStream, setLocalStream] = useState<MediaStream | null>(null);
  const [remoteStreams, setRemoteStreams] = useState<Map<string, RemoteParticipant>>(new Map());
  const [isConnected, setIsConnected] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const signalingClientRef = useRef<SignalingClient | null>(null);
  const webrtcClientRef = useRef<WebRTCClient | null>(null);
  const producerUserMapRef = useRef<Map<string, { userId: string; role: string }>>(new Map());

  const initializeClients = useCallback(async () => {
    try {
      // Initialize signaling client
      const wsProtocol = window.location.protocol === 'https:' ? 'wss:' : 'ws:';
      const wsHost = process.env.NODE_ENV === 'development' ? 'localhost:8080' : window.location.host;
      const wsUrl = `${wsProtocol}//${wsHost}/ws/signaling`;
      const signalingClient = new SignalingClient(wsUrl);
      await signalingClient.connect();
      signalingClientRef.current = signalingClient;

      // Join room
      const joinResponse = await signalingClient.send({
        type: 'join-room',
        roomId,
        role,
        userId,
      });

      console.log('Join response:', joinResponse);

      // Initialize WebRTC client
      const webrtcClient = new WebRTCClient(signalingClient, roomId);
      await webrtcClient.initialize();
      webrtcClientRef.current = webrtcClient;

      // Store existing producer info
      if (joinResponse.existingProducers) {
        for (const producer of joinResponse.existingProducers) {
          producerUserMapRef.current.set(producer.producerId, {
            userId: producer.userId || 'Unknown',
            role: producer.role || 'viewer',
          });
        }
      }

      // If there are existing producers, consume them
      if (joinResponse.existingProducers && joinResponse.existingProducers.length > 0) {
        console.log('Found existing producers:', joinResponse.existingProducers);

        await webrtcClient.createRecvTransport();

        // Group producers by userId to create one stream per participant
        const producersByUser = new Map<string, any[]>();
        for (const producer of joinResponse.existingProducers) {
          const odrive = producer.odrive || 'unknown';
          if (!producersByUser.has(odrive)) {
            producersByUser.set(producerId, []);
          }
          producersByUser.get(odrive)!.push(producer);
        }

        // Consume each producer
        for (const producer of joinResponse.existingProducers) {
          try {
            const odrive = producer.odrive || producer.producerId;

            await webrtcClient.consume(producer.producerId, (track) => {
              console.log('Received remote track from existing producer:', track.kind);

              setRemoteStreams((prev) => {
                const newStreams = new Map(prev);
                let participant = newStreams.get(odrive);

                if (!participant) {
                  participant = {
                    stream: new MediaStream(),
                    userId: producer.userId || 'Participant',
                    role: producer.role || 'viewer',
                  };
                  newStreams.set(odrive, participant);
                }

                participant.stream.addTrack(track);
                return newStreams;
              });
            });
          } catch (error: any) {
            console.error('Error consuming existing producer:', error);
          }
        }
      }

      // Listen for new producers from ANY participant
      signalingClient.on('new-producer', async (message) => {
        console.log('>>> NEW PRODUCER NOTIFICATION:', message);

        // Don't consume our own producers
        if (message.odrive === odrive) {
          console.log('Skipping own producer');
          return;
        }

        if (webrtcClientRef.current) {
          try {
            await webrtcClientRef.current.createRecvTransport();

            const odrive = message.odrive || message.producerId;

            // Store producer info
            producerUserMapRef.current.set(message.producerId, {
              userId: message.userId || 'Participant',
              role: message.role || 'viewer',
            });

            await webrtcClientRef.current.consume(message.producerId, (track) => {
              console.log('>>> Received remote track:', track.kind);

              setRemoteStreams((prev) => {
                const newStreams = new Map(prev);
                let participant = newStreams.get(odrive);

                if (!participant) {
                  participant = {
                    stream: new MediaStream(),
                    userId: message.userId || 'Participant',
                    role: message.role || 'viewer',
                  };
                  newStreams.set(odrive, participant);
                }

                participant.stream.addTrack(track);
                return newStreams;
              });
            });
          } catch (error: any) {
            console.error('>>> ERROR consuming producer:', error);
            setError(`Failed to consume stream: ${error.message}`);
          }
        }
      });

      setIsConnected(true);
      console.log('WebRTC clients initialized');
    } catch (error: any) {
      console.error('Error initializing clients:', error);
      setError(`Initialization failed: ${error.message}`);
      throw error;
    }
  }, [roomId, role, userId]);

  // Start producing media (for all participants)
  const startMedia = useCallback(async () => {
    try {
      setError(null);

      if (!webrtcClientRef.current) {
        await initializeClients();
      }

      // Get user media
      const stream = await mediaDevicesService.getUserMedia({ video: true, audio: true });
      setLocalStream(stream);

      // Create send transport
      await webrtcClientRef.current!.createSendTransport();

      // Produce tracks
      for (const track of stream.getTracks()) {
        await webrtcClientRef.current!.produce(track);
        console.log(`Producing ${track.kind} track`);
      }

      console.log('Media started');
    } catch (error: any) {
      console.error('Error starting media:', error);
      setError(`Failed to start media: ${error.message}`);
    }
  }, [initializeClients]);

  const stopMedia = useCallback(() => {
    if (localStream) {
      mediaDevicesService.stopStream(localStream);
      setLocalStream(null);
    }

    if (webrtcClientRef.current) {
      webrtcClientRef.current.close();
      webrtcClientRef.current = null;
    }

    console.log('Media stopped');
  }, [localStream]);

  const leave = useCallback(() => {
    if (webrtcClientRef.current) {
      webrtcClientRef.current.close();
      webrtcClientRef.current = null;
    }

    if (signalingClientRef.current) {
      signalingClientRef.current.send({
        type: 'leave-room',
        roomId,
      });
      signalingClientRef.current.close();
      signalingClientRef.current = null;
    }

    if (localStream) {
      mediaDevicesService.stopStream(localStream);
      setLocalStream(null);
    }

    setRemoteStreams(new Map());
    setIsConnected(false);
    producerUserMapRef.current.clear();

    console.log('Left room');
  }, [roomId, localStream]);

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      if (webrtcClientRef.current) {
        webrtcClientRef.current.close();
      }

      if (signalingClientRef.current) {
        signalingClientRef.current.send({
          type: 'leave-room',
          roomId,
        });
        signalingClientRef.current.close();
      }

      if (localStream) {
        mediaDevicesService.stopStream(localStream);
      }
    };
  }, []);

  return {
    localStream,
    remoteStreams,
    isConnected,
    error,
    startMedia,
    stopMedia,
    leave,
    signalingClient: signalingClientRef.current,
  };
}
